import * as math from 'mathjs';

type DataContext = Record<string, unknown>;

function evaluateFormula(template: string, data: DataContext): string {
  return template.replace(/\{\{(.+?)\}\}/g, (match, expression) => {
    const trimmed = expression.trim();

    try {
      // Build a scope from the data context
      const scope = flattenContext(data);

      // Evaluate the expression using mathjs
      const result = math.evaluate(trimmed, scope);

      if (result === undefined || result === null) {
        return match;
      }

      // Format the result nicely
      return formatResult(result);
    } catch {
      // If evaluation fails, try simple property access
      const value = getNestedValue(data, trimmed);
      if (value !== undefined) {
        return formatResult(value);
      }
      return match;
    }
  });
}

function flattenContext(
  data: DataContext,
  prefix = '',
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const [key, value] of Object.entries(data)) {
    const fullKey = prefix ? `${prefix}_${key}` : key;

    if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
      // Add the object itself
      result[fullKey] = value;
      // Also flatten nested properties
      flattenContext(value as DataContext, fullKey, result);
    } else {
      result[fullKey] = value;
    }

    // Also add with original key (no prefix) for top-level access
    if (!prefix) {
      result[key] = value;
    }
  }

  return result;
}

function getNestedValue(data: DataContext, path: string): unknown {
  const parts = path.split('.');
  let current: unknown = data;

  for (const part of parts) {
    if (current === null || current === undefined) return undefined;
    if (typeof current !== 'object') return undefined;
    current = (current as DataContext)[part];
  }

  return current;
}

function formatResult(value: unknown): string {
  if (typeof value === 'number') {
    // Avoid floating point noise like 0.30000000000000004
    const rounded = parseFloat(value.toPrecision(12));
    return String(rounded);
  }

  if (typeof value === 'boolean') {
    return String(value);
  }

  if (Array.isArray(value)) {
    return value.join(', ');
  }

  if (value instanceof Date) {
    return value.toLocaleDateString();
  }

  if (value !== null && typeof value === 'object') {
    return JSON.stringify(value);
  }

  return String(value ?? '');
}

