type DataContext = Record<string, unknown>;

function evaluateExpression(expression: string, data: DataContext): unknown {
  const paramNames = Object.keys(data);
  const paramValues = Object.values(data);

  const fn = new Function(...paramNames, `return (${expression});`);
  return fn(...paramValues);
}

function evaluateTemplate(template: string, data: DataContext): string {
  const pattern = /\{\{([\s\S]+?)\}\}/g;

  return template.replace(pattern, (match, expression) => {
    const trimmed = expression.trim();
    try {
      const result = evaluateExpression(trimmed, data);
      if (result === null || result === undefined) {
        return "";
      }
      return String(result);
    } catch (error) {
      throw new Error(
        `Failed to evaluate expression '${trimmed}': ${(error as Error).message}`
      );
    }
  });
}

export function createTemplateEvaluator(): (
  template: string,
  data: DataContext
) => string {
  return (template: string, data: DataContext): string => {
    return evaluateTemplate(template, data);
  };
