type DataContext = Record<string, unknown>;

interface EvaluationResult {
  result: string;
  errors: Array<{ expression: string; error: string }>;
}

function createSafeScope(data: DataContext): Record<string, unknown> {
  const scope: Record<string, unknown> = { ...data };

  // Add common math utilities
  scope.Math = Math;
  scope.Number = Number;
  scope.String = String;
  scope.Boolean = Boolean;
  scope.parseInt = parseInt;
  scope.parseFloat = parseFloat;
  scope.isNaN = isNaN;
  scope.isFinite = isFinite;
  scope.Array = Array;
  scope.Object = Object;
  scope.JSON = JSON;
  scope.Date = Date;

  return scope;
}

function sanitizeExpression(expression: string): string {
  return expression.trim();
}

function validateExpression(expression: string): void {
  const dangerousPatterns = [
    /\beval\b/,
    /\bFunction\b/,
    /\bfetch\b/,
    /\bXMLHttpRequest\b/,
    /\bimport\b/,
    /\brequire\b/,
    /\bprocess\b/,
    /\bglobal\b/,
    /\bwindow\b/,
    /\bdocument\b/,
    /\blocalStorage\b/,
    /\bsessionStorage\b/,
    /\bcookies\b/,
    /\b__proto__\b/,
    /\bprototype\b/,
    /\bconstructor\b/,
  ];

  for (const pattern of dangerousPatterns) {
    if (pattern.test(expression)) {
      throw new Error(
        `Expression contains disallowed pattern: ${pattern.source}`
      );
    }
  }

  // Validate that it's a valid expression using acorn
  try {
    acorn.parseExpressionAt(expression, 0, {
      ecmaVersion: 2020,
    });
  } catch (e) {
    throw new Error(
      `Invalid expression syntax: ${e instanceof Error ? e.message : String(e)}`
    );
  }
}

function evaluateExpression(
  expression: string,
  data: DataContext
): unknown {
  const sanitized = sanitizeExpression(expression);
  validateExpression(sanitized);

  const scope = createSafeScope(data);
  const scopeKeys = Object.keys(scope);
  const scopeValues = scopeKeys.map((key) => scope[key]);

  // Parse the expression with acorn to get the AST
  const ast = acorn.parseExpressionAt(sanitized, 0, {
    ecmaVersion: 2020,
  });

  // Generate code from AST using astring (ensures clean code)
  const cleanExpression = astring.generate(ast as astring.AstNode);

  // Create a function with the scope variables as parameters
  // eslint-disable-next-line no-new-func
  const fn = new Function(...scopeKeys, `"use strict"; return (${cleanExpression});`);

  return fn(...scopeValues);
}

