import * as ts from "typescript";

type DataContext = Record<string, unknown>;

function evaluateExpression(expression: string, data: DataContext): unknown {
  const keys = Object.keys(data);
  const values = Object.values(data);

  const fnBody = `return (${expression});`;
  const fn = new Function(...keys, fnBody);

  return fn(...values);
}

function createTemplateEvaluator() {
  return function evaluateTemplate(
    template: string,
    data: DataContext
  ): string {
    const pattern = /\{\{([\s\S]+?)\}\}/g;

    return template.replace(pattern, (match, expression) => {
      const trimmed = expression.trim();

      try {
        const result = evaluateExpression(trimmed, data);

        if (result === null || result === undefined) {
          return "";
        }

        if (typeof result === "number" && !Number.isFinite(result)) {
          return String(result);
        }

        return String(result);
      } catch (error) {
        const message =
          error instanceof Error ? error.message : "Unknown error";
        return `[Error: ${message}]`;
      }
    });
  };
}

