import * as math from 'mathjs';

type DataContext = Record<string, unknown>;

function evaluateFormula(template: string, data: DataContext): string {
  return template.replace(/\{\{(.*?)\}\}/g, (match, expression) => {
    const trimmed = expression.trim();

    try {
      // Build a scope from the data context
      const scope = flattenContext(data);

      // Evaluate the expression using mathjs
      const result = math.evaluate(trimmed, scope);

      if (result === undefined || result === null) {
        return match; // Return original if no result
      }

      // Format numbers nicely
      if (typeof result === 'number') {
        return formatNumber(result);
      }

      return String(result);
    } catch {
      // If evaluation fails, try direct property lookup
      const value = getNestedValue(data, trimmed);
      if (value !== undefined) {
        return String(value);
      }

      return match; // Return original placeholder if all else fails
    }
  });
}

function flattenContext(
  data: DataContext,
  prefix = '',
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const [key, value] of Object.entries(data)) {
    const fullKey = prefix ? `${prefix}_${key}` : key;

    if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
      // Add the object itself
      result[fullKey] = value;
      // Also flatten nested properties
      flattenContext(value as DataContext, fullKey, result);
    } else {
      result[fullKey] = value;
    }

    // Also add with original key for top-level
    if (!prefix) {
      result[key] = value;
    }
  }

  return result;
}

function getNestedValue(obj: DataContext, path: string): unknown {
  const parts = path.split('.');
  let current: unknown = obj;

  for (const part of parts) {
    if (current === null || current === undefined) {
      return undefined;
    }
    current = (current as DataContext)[part];
  }

  return current;
}

function formatNumber(num: number): string {
  // If it's an integer, return without decimals
  if (Number.isInteger(num)) {
    return num.toString();
  }

  // Round to reasonable precision to avoid floating point artifacts
  const rounded = parseFloat(num.toPrecision(10));
  return rounded.toString();
}

